const fs = require('fs');
function readLog(fileName) {
    return new Promise((resolve, reject) => {
        try{
            const data = fs.readFileSync(fileName);
            resolve(data);
        } catch (err){
            reject(err);
        }
    });
}
module.exports = readLog;